/** A single task row. */

import { formatTitle } from '../utils/format';
import type { Task } from '../types';

export interface TaskItemProps {
  task: Task;
  onComplete: (id: number) => void;
}

export function TaskItem({ task, onComplete }: TaskItemProps) {
  return (
    <li className={`task task--${task.status}`}>
      <span className="task__title">{formatTitle(task.title)}</span>
      <button onClick={() => onComplete(task.id)} disabled={task.status === 'done'}>
        done
      </button>
    </li>
  );
}

